const stats = [
  { value: "13,751", label: "Online Services" },
  { value: "5,456", label: "Govt. Schemes" },
  { value: "8,834", label: "Citizen Engagements" },
  { value: "3,897", label: "Tourist Places" },
  { value: "1,207", label: "ODOP Products" },
  { value: "18", label: "Information Categories" },
];

export default function Stats() {
  return (
    <section className="relative z-20 -mt-[72px] px-4 sm:-mt-20 sm:px-6">
      <div className="glass-card mx-auto max-w-[1200px] rounded-xl px-5 py-8 sm:px-10 sm:py-10">
        <div className="grid grid-cols-2 gap-y-8 gap-x-4 md:grid-cols-3 lg:grid-cols-6 lg:gap-y-6">
          {stats.map((item) => (
            <div
              key={item.label}
              className="group border-r-0 text-center last:border-0 lg:border-r lg:border-gray-100 lg:last:border-r-0"
            >
              <p className="text-[1.75rem] font-bold leading-none text-[#0a2a6e] sm:text-[2rem] lg:text-[2.1rem]">
                {item.value}
              </p>
              <p className="mx-auto mt-2.5 max-w-[120px] text-xs leading-snug text-gray-600 sm:text-[13px]">
                {item.label}
              </p>
              <div className="mx-auto mt-3 h-0.5 w-0 bg-[#e31e24] transition-all duration-300 group-hover:w-8" />
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
